mapper.select:
SELECT IFNULL(SUM(shipped_qty), 0)
FROM sal_order_item soi
         LEFT JOIN sal_order so ON soi.order_id = so.id
WHERE soi.material_id = #{materialId}
  AND so.create_time BETWEEN #{start} AND #{end}
  AND so.is_deleted = 0

SELECT IFNULL(SUM(soi.amount), 0)
FROM sal_order_item soi
         LEFT JOIN sal_order so ON soi.order_id = so.id
WHERE soi.material_id = #{materialId}
  AND so.create_time BETWEEN #{start} AND #{end}
  AND so.is_deleted = 0
